import { ElectronAPI, FileMetadata, FileNode } from '../types';
import { structure as contentStructure, loadContent } from 'virtual:solo-content';

/**
 * In-memory file store for packaged (web) builds.
 *
 * The note tree comes from the `--content <folder>` build flag: the
 * {@link contentStructure} (generated by the `solo-content` Vite plugin) provides
 * the folder/file hierarchy plus metadata, while the note HTML is fetched lazily
 * via {@link loadContent} the first time a note is opened.
 *
 * Notes can still be created, edited, renamed and deleted entirely in memory.
 */

// ── File content storage (path → HTML string) ──
// Holds notes created/edited in memory as well as lazily loaded note contents.
const fileContents = new Map<string, string>();

// ── Metadata storage (path → FileMetadata) ──
const metadatas = new Map<string, FileMetadata>();

// ── Live tree used by readStructure(); mutated by create/rename/delete ops. ──
let structure: FileNode[] = [];

// ── Paths of notes whose content can be lazily loaded from the content bundle. ──
const lazyPaths = new Set<string>();

let idCounter = 0;

function nextId(): string {
  return `mem-${++idCounter}-${Date.now()}`;
}

/** Generate a unique .html path within a parent folder */
function makeHtmlPath(parentPath: string, title: string): string {
  const safeName = title.replace(/[/\\?%*:|"<>]/g, '_').slice(0, 100);
  const fileName = `${safeName} - ${Date.now()}.html`;
  return parentPath ? `${parentPath}/${fileName}` : fileName;
}

