/** Deep clone a FileNode tree so runtime mutations don't touch the build-time data. */
function cloneStructure(nodes: FileNode[]): FileNode[] {
  return nodes.map((node) => ({
    ...node,
    metadata: node.metadata ? { ...node.metadata } : undefined,
    children: node.children ? cloneStructure(node.children) : undefined,
  }));
}

/** Walk a tree registering metadata and, for content-backed notes, lazy paths. */
function indexTree(nodes: FileNode[], lazy: boolean) {
  for (const node of nodes) {
    if (node.type === 'folder') {
      if (node.children) indexTree(node.children, lazy);
      continue;
    }
    if (node.metadata) {
      metadatas.set(node.path, node.metadata);
    }
    if (lazy && node.path.endsWith('.html')) {
      lazyPaths.add(node.path);
    }
  }
}

// ── Initialise the store from the content bundle (or demo fallback). ──
function initStore() {
  if (contentStructure && contentStructure.length > 0) {
    structure = cloneStructure(contentStructure);
    indexTree(structure, true);
  } else {
    seedDemoFiles();
    structure = buildStaticStructure();
    indexTree(structure, false);
  }
}

initStore();

/** Read a note's content, lazily loading it from the content bundle if needed. */
async function readContent(relativePath: string): Promise<string | undefined> {
  if (fileContents.has(relativePath)) {
    return fileContents.get(relativePath);
  }
  if (lazyPaths.has(relativePath)) {
    const content = await loadContent(relativePath);
    if (content !== null && content !== undefined) {
      fileContents.set(relativePath, content);
      return content;
    }
  }
  return undefined;
}

// ── Tree mutation helpers (operate on the live `structure`) ──

function findParentList(targetPath: string): FileNode[] {
  const parentPath = targetPath.includes('/')
    ? targetPath.slice(0, targetPath.lastIndexOf('/'))
    : '';
  if (!parentPath) return structure;

  let current: FileNode[] = structure;
  const segments = parentPath.split('/');
  let acc = '';
  for (const segment of segments) {
    acc = acc ? `${acc}/${segment}` : segment;
    const folder = current.find((n) => n.path === acc && n.type === 'folder');
    if (!folder) return structure;
    if (!folder.children) folder.children = [];
    current = folder.children;
  }
  return current;
}

function removeNode(targetPath: string): FileNode | undefined {
  const list = findParentList(targetPath);
  const idx = list.findIndex((n) => n.path === targetPath);
  if (idx === -1) return undefined;
  return list.splice(idx, 1)[0];
}

function rebasePaths(node: FileNode, oldBase: string, newBase: string) {
  node.path = node.path === oldBase ? newBase : newBase + node.path.slice(oldBase.length);
  if (node.children) {
    for (const child of node.children) rebasePaths(child, oldBase, newBase);
  }
}

/** Create a stub ElectronAPI that works fully in memory for packaged web builds. */
export function createStubAPI(): ElectronAPI {
  const stub: {
    [K in keyof ElectronAPI]: (...args: any[]) => Promise<any>;
  } = {
    // ── Folder / file operations (not available, but return gracefully) ──
    selectFolder: async () => {
      return { success: false, error: 'Not available in packaged build' };
    },
    getDataFolder: async () => {
      return { success: false, error: 'Not available in packaged build' };
    },
    selectParentFolder: async () => {
      return { success: false, error: 'Not available in packaged build' };
    },

    // ── In-memory read / write (with lazy content loading) ──
    openFile: async (relativePath: string) => {
      const content = await readContent(relativePath);
      if (content === undefined) {
        return { success: false, error: `File "${relativePath}" not found in memory` };
      }
      return { success: true, content };
    },
    updateFile: async (relativePath: string, content: string) => {
      fileContents.set(relativePath, content);
      return { success: true };
    },
    updateMetadata: async (relativePath: string, metadata: FileMetadata) => {
      metadatas.set(relativePath, metadata);
      return { success: true };
    },
    readStructure: async () => {
      return { success: true, structure };
    },

    // ── Tag scanning ──
    scanAllTags: async () => {
      const tags = new Set<string>();
      for (const meta of metadatas.values()) {
        meta.tags?.forEach((tag) => tags.add(tag));
        meta.paragraphTags?.forEach((tag) => tags.add(tag));
      }
      return { success: true, tags: Array.from(tags).sort() };
    },

    // ── Zen mode ──
    toggleZenMode: async () => {
      return { success: false, error: 'Not available in packaged build' };
    },
    getZenMode: async () => {
      return { success: true, isZenMode: false };
    },

    // ── Search (in-memory, lazily loads content when needed) ──
    search: async (searchString?: string, tags?: string[]) => {
      const results: Array<{ path: string; type: string; matches: string[]; metadata?: FileMetadata }> = [];
      const hasSearchString = searchString && searchString.trim().length > 0;
      const hasTags = tags && tags.length > 0;

      if (!hasSearchString && !hasTags) {
        return { success: true, results: [] };
      }

      const searchLower = searchString?.toLowerCase() || '';

      // Collect all known note paths from content store, metadata and lazy paths.
      const allPaths = new Set([
        ...fileContents.keys(),
        ...metadatas.keys(),
        ...lazyPaths,
      ]);

      for (const filePath of allPaths) {
        const matches: string[] = [];
        const meta = metadatas.get(filePath);
        const fileName = filePath.split('/').pop() || filePath;

        // ── Filename match ──
        if (hasSearchString && fileName.toLowerCase().includes(searchLower)) {
          matches.push('filename');
        }

        // ── Content match (HTML notes only) ──
        if (hasSearchString && filePath.endsWith('.html')) {
          const content = await readContent(filePath);
          if (content && content.toLowerCase().includes(searchLower)) {
            matches.push('content');
          }
        }

        // ── Metadata / tag matching ──
        if (meta) {
          if (hasTags && meta.tags) {
            const hasMatchingTag = tags!.some(tag =>
              meta.tags!.some(metaTag =>
                metaTag.toLowerCase().includes(tag.toLowerCase())
              )
            );
            if (hasMatchingTag) {
              matches.push('metadata:tags');
            }
          }

          if (hasSearchString) {
            if (meta.id?.toLowerCase().includes(searchLower)) {
              matches.push('metadata:id');
            }
            if (meta.tags?.some(tag => tag.toLowerCase().includes(searchLower))) {
              matches.push('metadata:tags');
            }
          }
        }

        if (matches.length > 0) {
          results.push({
            path: filePath,
            type: matches.includes('content') ? 'content' : 'filename',
            matches: [...new Set(matches)],
            metadata: meta,
          });
        }
      }

      return { success: true, results };
    },

    // ── Notebooks (in-memory) ──
    createNotebook: async (parentPath: string, name: string) => {
      const path = parentPath ? `${parentPath}/${name}` : name;
      const list = findParentList(path);
      if (!list.some((n) => n.path === path)) {
        list.push({ name, path, type: 'folder', children: [] });
      }
      return { success: true, path };
    },
    deleteNotebook: async (relativePath: string) => {
      removeNode(relativePath);
      return { success: true };
    },
    renameNotebook: async (relativePath: string, newName: string) => {
      const parts = relativePath.split('/');
      parts[parts.length - 1] = newName;
      const newPath = parts.join('/');
      const list = findParentList(relativePath);
      const node = list.find((n) => n.path === relativePath);
      if (node) {
        node.name = newName;
        rebasePaths(node, relativePath, newPath);
      }
      return { success: true, newPath };
    },

    // ── Notes (in-memory) ──
    createNote: async (parentPath: string, name: string) => {
      const id = nextId();
      const htmlPath = makeHtmlPath(parentPath, name);
      const now = new Date().toISOString();
      const metadata: FileMetadata = {
        id,
        tags: [],
        createdAt: now,
        theme: '',
        paragraphTags: [],
      };
      fileContents.set(htmlPath, '');
      metadatas.set(htmlPath, metadata);
      const list = findParentList(htmlPath);
      list.push({
        name: htmlPath.split('/').pop() || htmlPath,
        path: htmlPath,
        type: 'file',
        metadata,
      });
      return { success: true, htmlPath, id };
    },
    deleteNote: async (relativePath: string) => {
      fileContents.delete(relativePath);
      metadatas.delete(relativePath);
      lazyPaths.delete(relativePath);
      removeNode(relativePath);
      return { success: true };
    },
    renameNote: async (relativePath: string, newName: string) => {
      const parts = relativePath.split('/');
      const ext = parts[parts.length - 1].includes('.') ? '.' + parts[parts.length - 1].split('.').pop() : '.html';
      parts[parts.length - 1] = newName.replace(/[^a-zA-Zа-яА-Я0-9 _-]/g, '') + ext;
      const newPath = parts.join('/');

      // Ensure content is materialised before moving (in case it was lazy).
      const content = await readContent(relativePath);
      const meta = metadatas.get(relativePath);
      if (content !== undefined) {
        fileContents.set(newPath, content);
        fileContents.delete(relativePath);
      }
      if (meta) {
        metadatas.set(newPath, meta);
        metadatas.delete(relativePath);
      }
      lazyPaths.delete(relativePath);

      const list = findParentList(relativePath);
      const node = list.find((n) => n.path === relativePath);
      if (node) {
        node.name = newPath.split('/').pop() || newPath;
        node.path = newPath;
      }
      return { success: true, newPath };
    },

    // ── PDF ──
    openPdfFile: async () => {
      return { success: false, error: 'Not available in packaged build' };
    },

    // ── File picker ──
    selectFile: async () => {
      return { success: false, error: 'Not available in packaged build' };
    },

    // ── Digikam ──
    getDigikamTags: async () => {
      return { success: false, error: 'Not available in packaged build' };
    },
    getDigikamImagesByTag: async () => {
      return { success: false, error: 'Not available in packaged build', digikamTag: '' };
    },
  };
  return stub as unknown as ElectronAPI;
}
